script.text:

function loadFormDir(f) {
  if (f._action == 'Edit') setItemDisable(f, 'ma_so', true);
    else if (f._action == 'New') setItemDisable(f, 'ma_so', false);
  onChange$OffBalanceSheet(f);
}
function onChange$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'stt':
      if (f.getItem('stt_in').value == '') f.getItem('stt_in').value = o.value;
      break;
    case 'ma_so':
      if (f.getItem('ma_so_me').value == '') f.getItem('ma_so_me').value = o.value.toUpperCase();
      break;
    case 'kind':
      onChange$CalculateType(f, true);
      break;
    case 'tk':
		case 'tk_du':
			onChange$RefAccount(f, true);
      break;
		default:
      break;
  }
}
function onChange$OffBalanceSheet(f, force) {window.setTimeout(String.format('onFocus$OffBalanceSheet(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$OffBalanceSheet(id, force) {
  var f = $find(id), v = (f.getItem('kind') == 0), t2 = f._findButton('Ok');
	if (force) setItemLive(t1, t2, !v);
  if (v) setItemDisable(f, 'tk, tk_du, tk_gt, ma_bp, ma_phi', v);
  else {
   setItemDisable(f, 'cach_tinh', v);
   onChange$CalculateType(f);
	 onChange$RefAccount(f);
  }
}
function onChange$CalculateType(f, force) {window.setTimeout(String.format('onFocus$CalculateType(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$CalculateType(id, force) {
  var f = $find(id), v = (f.getItem('kind').value == 0), t1 = f.getItem('tk'), t2 = f.getItem('cach_tinh');
  setFieldsEmpty(f, 'cach_tinh', v);
	if (force) setItemLive(t1, t2, !v);
  setItemDisable(f, 'cach_tinh', !v);
	setItemDisable(f, 'tk, tk_du, ma_bp, ma_phi, no_co', v);
	setFieldsEmpty(f, 'tk_du, ma_bp, ma_phi', !v);
}

function onChange$RefAccount(f, force) {window.setTimeout(String.format('onFocus$RefAccount(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$RefAccount(id, force) {
  var f = $find(id), t1 = f.getItem('tk_gt'), t2 = f.getItem('ma_bp'), v1 = f.getItemValue('tk'), v2 = f.getItemValue('tk_du');
  v = ((v1 != '' && v2 == '') || (v1 == '' && v2 != ''));	 
	setItemDisable(f, 'tk_gt', !v);
	setFieldsEmpty(f, 'tk_gt', v);	
	if (force) setItemLive(t1, t2, v); 
}

function setItemLive(t1, t2, type) {
  if (type) {if (t2.live) {t1.disabled = false; t1.focus();}}
    else {if (t1.live) {t2.disabled = false; t2.focus();}}
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}

      &ScriptIrregular;
